class Solution {
    private static final int MOD = (int)1e9 + 7;
    private static final int N = 10010;
    private static final int[][] dp = new int[N][7];
    private static final int[][] gcd = new int[7][7];

    static {
        for (int i = 1; i <= 6; i++) {
            for (int j = 1; j <= 6; j++) {
                gcd[i][j] = gcd(j, i);
                if (j == 0) {
                    gcd[i][j] = i;
                } else if (i < j) {
                    gcd[i][j] = gcd(j, i);
                } else {
                    gcd[i][j] = gcd(i % j, j);
                }
            }
        }
    }

    public int distinctSequences(int n) {
        Arrays.fill(dp[0], 1);
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= 6; j++) {
                for (int k = 1; k <= 6; k++) {
                    if (gcd[j][k] == 1 && (i == 1 || k != dp[i - 1][j])) {
                        dp[i][j] = (dp[i][j] + dp[i - 1][k]) % MOD;
                    }
                }
            }
        }
        int res = 0;
        for (int i = 1; i <= 6; i++) {
            res = (res + dp[n][i]) % MOD;
        }
        return res;
    }
}
